sql:
SELECT DISTINCT u.username 
FROM users u 
JOIN comments c ON u.user_id = c.user_id;

SELECT post_id, COUNT(DISTINCT tag_id) AS unique_tag_count
FROM post_tags
GROUP BY post_id;

SELECT AVG(num_comments) AS average_comments_per_user
FROM (
    SELECT COUNT(comment_id) AS num_comments
    FROM comments
    GROUP BY user_id
) AS comment_counts;

SELECT * 
FROM posts 
WHERE post_id NOT IN (SELECT post_id FROM post_history WHERE change_type = 'deleted');

SELECT title, favorite_count, view_count, sdlc_stage_id 
FROM posts 
WHERE favorite_count IN (
  (SELECT MAX(favorite_count) FROM posts WHERE favorite_count > 0), 
  (SELECT MIN(favorite_count) FROM posts WHERE favorite_count > 0)
);

SELECT AVG(NumComments) 
FROM (
    SELECT COUNT(*) AS NumComments 
    FROM comments 
    GROUP BY user_id
);

external_knowledge:
Troublesome entries refer to posts that have been flagged as problematic (is_problematic = 1); SDLC stages are crucial phases in software development lifecycle tracking.;
Problematic posts are those that have been marked with a reason for concern, captured in the problematic_flags table.; 
The original_id in the posts table and user_id in the users table are used to link the post to its author for identification purposes.
